// ─── Expand Board URLs ────────────────────────────────────────────────────
// Converts the jobBoards array from Config into individual n8n items
// so the RSS Reader can process each feed one at a time.
//
// Input:  { jobBoards: ["url1", "url2", "url3"] }
// Output: three separate items, one per URL

const config = $input.first().json;
const jobBoards = Array.isArray(config.jobBoards) ? config.jobBoards : [];

if (jobBoards.length === 0) {
  throw new Error('No job board URLs found in Config. Add at least one RSS URL to the jobBoards array.');
}

return jobBoards.map(url => ({
  json: { jobBoards: url.trim() }
}));

// ─── Log RSS Fetch Error ──────────────────────────────────────────────────
// Catches failed RSS feed requests without stopping the loop.
// Errors are logged to n8n execution logs; the loop continues normally.

const item = $input.first();

// Identify which feed failed
const feedUrl = item.json.jobBoards
             ?? item.json.url
             ?? item.json.link
             ?? 'unknown feed';

const errorMsg = item.json.error?.message
              ?? item.json.error
              ?? (typeof item.json.statusCode === 'number' ? `HTTP ${item.json.statusCode}` : null)
              ?? 'connection failed or feed unreachable';

console.error(`[Job Digest] RSS feed failed → ${feedUrl} — ${errorMsg}`);

// Returning [] means no items flow forward from this branch.
// The connection back to Split Job Boards continues the loop.
return [];

// ─── Normalize Jobs ───────────────────────────────────────────────────────
// Standardises raw RSS fields into a consistent schema.
// Different feeds use different field names for the same data — this node
// unifies them so downstream nodes can work with a single predictable shape.
//
// Output schema per item:
// { title, company, url, datePosted, categories, content, source, scrapedAt }

const sourceURL = $('Split Job Boards').first().json.jobBoards ?? '';
const regex = /(?:https?:\/\/)?(?:www\.)?([^\/\s\.]+)/;
const regexMatch = sourceURL.match(regex);
const detectedSource = regexMatch ? regexMatch[1] : 'unknown';

function normalizeDate(raw) {
  if (!raw) return '';
  raw = String(raw).trim();
  // Already ISO 8601
  if (/^\d{4}-\d{2}-\d{2}/.test(raw)) return raw;
  // Unix timestamp (10 or 13 digits)
  if (/^\d{10,13}$/.test(raw)) {
    const ms = raw.length === 10 ? parseInt(raw, 10) * 1000 : parseInt(raw, 10);
    return new Date(ms).toISOString();
  }
  // Human-readable / RFC 2822 (common in RSS feeds)
  const parsed = Date.parse(raw);
  if (!isNaN(parsed)) return new Date(parsed).toISOString();
  return raw; // Return as-is if unparseable; recency filter will skip it
}

const output = [];
const scrapedAt = new Date().toISOString();

for (const item of $input.all()) {
  const raw = item.json;

  const title      = (raw.title       ?? '').trim().replace(/\s+/g, ' ');
  const content    = (raw.contentSnippet ?? raw.content ?? '').trim().replace(/\s+/g, ' ');
  const categories = Array.isArray(raw.categories)
                       ? raw.categories.join(' , ')
                       : (raw.categories ?? '');
  const company    = (raw.company     ?? '').trim().replace(/\s+/g, ' ');

  // Try multiple URL fields in order of preference
  const rawUrl = raw.url ?? raw.applyUrl ?? raw.link ?? raw.guid ?? '';
  const url = rawUrl.trim();

  const date = raw.isoDate
             ?? normalizeDate(raw.datePosted ?? raw.date ?? raw.pubDate ?? '');

  // Skip entries with no title or no URL — they're not usable
  if (!title || !url) continue;

  output.push({
    json: {
      title,
      company:    company || 'Unknown Company',
      url,
      datePosted: date,
      categories,
      content,
      source:     raw.sourceName ?? detectedSource,
      scrapedAt,
    }
  });
}

return output;

// ─── Filter by Keyword & Recency ─────────────────────────────────────────
// Reads keywords and maxAgeHours from the Config node.
//
// Keyword matching: case-insensitive, checks title + company + content + categories
// Recency: drops jobs older than maxAgeHours (default 24h)
//
// ⚠️  alwaysOutputData is ON — this ensures the Split/Loop continues
// even when zero items match. Do not disable it.

const config      = $('Config').first().json;
const keywords    = (config.keywords   ?? []).map(k => k.toLowerCase().trim()).filter(Boolean);
const maxAgeHours = config.maxAgeHours ?? 24;
const maxAgeMs    = maxAgeHours * 60 * 60 * 1000;
const now         = Date.now();

const output = [];

for (const item of $input.all()) {
  const { title, company, datePosted, content, categories } = item.json;

  // ── Keyword filter (skip if keywords list is empty = accept all) ─────────
  if (keywords.length > 0) {
    const haystack = `${title} ${company} ${content} ${categories}`.toLowerCase();
    const matches  = keywords.some(kw => haystack.includes(kw));
    if (!matches) continue;
  }

  // ── Recency filter ────────────────────────────────────────────────────────
  if (datePosted) {
    const postedMs = new Date(datePosted).getTime();
    // Only filter if the date was parseable; otherwise let it through
    if (!isNaN(postedMs) && now - postedMs > maxAgeMs) continue;
  }

  output.push(item);
}

return output;

// ─── Deduplicate Jobs ────────────────────────────────────────────────────
// Uses $getWorkflowStaticData('global') to persist seen job URLs across
// workflow executions in the n8n database.
//
// First run:  all jobs are new → all pass through
// Later runs: only jobs with URLs not seen before pass through
//
// Auto-maintenance:
//   - Entries older than 30 days are purged on every run
//   - Maximum 2,000 entries; oldest are dropped if exceeded
//
// ⚠️  alwaysOutputData is ON — ensures the loop continues even when
// all incoming jobs are duplicates. Do not disable it.

const MAX_SEEN_ENTRIES = 2000;
const MAX_AGE_MS       = 30 * 24 * 60 * 60 * 1000; // 30 days

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenJobs) staticData.seenJobs = {};

// ── Purge entries older than 30 days ──────────────────────────────────────
const now = Date.now();
for (const [url, ts] of Object.entries(staticData.seenJobs)) {
  if (now - new Date(ts).getTime() > MAX_AGE_MS) {
    delete staticData.seenJobs[url];
  }
}

// ── Enforce size cap: drop oldest entries first ───────────────────────────
let entries = Object.entries(staticData.seenJobs);
if (entries.length > MAX_SEEN_ENTRIES) {
  entries.sort((a, b) => new Date(a[1]) - new Date(b[1]));
  const toDrop = entries.slice(0, entries.length - MAX_SEEN_ENTRIES);
  for (const [url] of toDrop) delete staticData.seenJobs[url];
}

// ── Identify jobs not yet seen ────────────────────────────────────────────
const newJobs = [];
for (const item of $input.all()) {
  const url = item.json.url;
  if (!url) continue;
  if (staticData.seenJobs[url]) continue; // already sent
  newJobs.push(item);
}

// ── Mark new jobs as seen (written to DB at end of execution) ─────────────
const seenAt = new Date().toISOString();
for (const item of newJobs) {
  staticData.seenJobs[item.json.url] = seenAt;
}

// Returning empty array is intentional when all jobs are duplicates.
// alwaysOutputData: true ensures the loop still continues.
return newJobs.length > 0 ? newJobs : [];

// ─── Build Email HTML ────────────────────────────────────────────────────
// Generates the full digest email from the aggregated jobs array.
// Outputs: { subject, html, jobCount }

const allItems = $input.all();

// Aggregate node wraps all items into data[]; handle both paths
let jobs = [];
if (allItems.length === 1 && Array.isArray(allItems[0].json.data)) {
  jobs = allItems[0].json.data;
} else {
  jobs = allItems.map(i => i.json);
}

// Drop any ghost empty objects (e.g. from alwaysOutputData passthrough)
jobs = jobs.filter(job => {
  if (!job || typeof job !== 'object') return false;
  return Object.values(job).some(v =>
    v !== null && v !== undefined && !(typeof v === 'string' && v.trim() === '')
  );
});

const jobCount = jobs.length;
const todayStr = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});
const runAt = new Date().toUTCString();

// ── Empty-state guard ─────────────────────────────────────────────────────
if (jobCount === 0) {
  return [{
    json: {
      subject: `Remote Job Digest — No New Jobs Today (${todayStr})`,
      html: `<html><body style="font-family:Arial,sans-serif;padding:32px;color:#555;">
               <p>No new remote jobs matched your filters today. Check back tomorrow!</p>
             </body></html>`,
      jobCount: 0,
    }
  }];
}

function formatDate(iso) {
  if (!iso) return '—';
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function escapeHtml(str) {
  return String(str ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const rows = jobs.map((job, i) => {
  const bg = i % 2 === 0 ? '#ffffff' : '#f9f9f9';
  return `
    <tr style="background:${bg};">
      <td style="padding:12px 16px;border-bottom:1px solid #eee;vertical-align:top;">
        <a href="${escapeHtml(job.url)}"
           style="color:#1a73e8;font-weight:600;text-decoration:none;font-size:14px;">
          ${escapeHtml(job.title)}
        </a>
        <div style="font-size:12px;color:#888;margin-top:3px;">
          ${escapeHtml(job.source)}
        </div>
      </td>
      <td style="padding:12px 16px;border-bottom:1px solid #eee;vertical-align:top;
                 font-size:13px;color:#666;white-space:nowrap;">
        ${formatDate(job.datePosted)}
      </td>
    </tr>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#f4f6f8;font-family:Arial,Helvetica,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f4f6f8;padding:32px 0;">
    <tr><td align="center">
      <table width="640" cellpadding="0" cellspacing="0"
             style="background:#fff;border-radius:8px;overflow:hidden;
                    box-shadow:0 2px 8px rgba(0,0,0,.08);max-width:100%;">
        <tr>
          <td style="background:#1a73e8;padding:24px 32px;">
            <h1 style="margin:0;color:#fff;font-size:22px;font-weight:700;">Remote Job Digest</h1>
            <p style="margin:4px 0 0;color:#d0e4ff;font-size:13px;">${todayStr}</p>
          </td>
        </tr>
        <tr>
          <td style="padding:12px 32px;background:#eef4ff;border-bottom:1px solid #d0e4ff;">
            <p style="margin:0;font-size:13px;color:#1a73e8;">
              <strong>${jobCount} new job${jobCount === 1 ? '' : 's'}</strong> matched your filters.
            </p>
          </td>
        </tr>
        <tr>
          <td style="padding:0 16px;">
            <table width="100%" cellpadding="0" cellspacing="0">
              <thead>
                <tr style="background:#f0f4ff;">
                  <th style="padding:10px 16px;text-align:left;font-size:11px;color:#555;
                             text-transform:uppercase;border-bottom:2px solid #dde8ff;">Position</th>
                  <th style="padding:10px 16px;text-align:left;font-size:11px;color:#555;
                             text-transform:uppercase;border-bottom:2px solid #dde8ff;
                             white-space:nowrap;">Posted</th>
                </tr>
              </thead>
              <tbody>${rows}</tbody>
            </table>
          </td>
        </tr>
        <tr>
          <td style="padding:20px 32px;border-top:1px solid #eee;background:#fafafa;text-align:center;">
            <p style="margin:0;font-size:11px;color:#aaa;">
              Generated by n8n Remote Job Digest &nbsp;·&nbsp; ${runAt}
            </p>
            <p style="margin:6px 0 0;font-size:11px;color:#aaa;">
              Duplicate jobs are automatically filtered across runs.
            </p>
          </td>
        </tr>
      </table>
    </td></tr>
  </table>
</body></html>`;

return [{
  json: {
    subject: `Remote Job Digest — ${jobCount} New Job${jobCount === 1 ? '' : 's'} (${todayStr})`,
    html,
    jobCount
  }
}];
